location ~ ~$ {
    deny all;
    access_log off;
    log_not_found off;
}

# WordPress: bloquear wp-config.php e outros arquivos sensíveis
location ~* /(?:uploads|files)/.*\.php$ {
    deny all;
}

# Bloquear acesso direto a "archives" de diretório em uploads, como:
# /wp-content/uploads/2026
# /wp-content/uploads/2026/04
# Isso não é archive do WordPress; é path estático resolvido pelo Nginx.
# Nota: usa [0-9][0-9]... em vez de {N} porque nginx parseia chaves como blocos
location ~ "^(?:/[_0-9a-zA-Z-]+)?/wp-content/uploads/[0-9][0-9][0-9][0-9](?:/[0-9][0-9])?/?$" {
    return 404;
}

# Uploads do blog principal: arquivo nao encontrado retorna 404 puro,
# nunca cai no PHP (evita WP renderizar archive.php "Arquivos" em URLs malformadas).
# ^~ tem prioridade sobre regex location ~* abaixo; multisite subsites
# (ex: /cultura/wp-content/uploads/) sao resolvidos pelas locations
# ^/[_0-9a-zA-Z-]+/(wp-content/.+)$ que reescrevem ANTES de chegar aqui.
location ^~ /wp-content/uploads/ {
    try_files $uri =404;
}

location ~* ^/(wp-config\.php|wp-config\.txt|readme\.html|license\.txt) {
    deny all;
}

# Bloquear indexacao de PDFs pelo Google
# PDFs devem ser acessados via pagina de publicacao, nao diretamente

