1	<?php
2	/**
3	 * Plugin Name: BIT — Elementor Local Cache (bypass S3-Uploads)
4	 * Description: Mantem o cache CSS do Elementor no filesystem local, fora do S3.
5	 * Version: 2.0.3
6	 * Author: Daniel Cambria / Bureau de Tecnologia
7	 *
8	 * Por que: o plugin S3-Uploads desvia /uploads/ para s3://. O cache CSS gerado pelo
9	 * Elementor (em /uploads/elementor/) iria pro S3 tambem. Como blue e green geram CSS
10	 * com IDs/slugs diferentes pos-import de DB, isso causaria sobrescrita cruzada.
11	 *
12	 * Solucao v2.0.0 (substitui v1.x — debug_backtrace nao funcionava):
13	 *
14	 *   1) PRE-WARM do static cache do Elementor com path LOCAL antes do S3-Uploads
15	 *      popular. Elementor 3.35.x tem `Base::$wp_uploads_dir[$blog_id]` que e
16	 *      memoizado por request (core/files/base.php:18,296-303). A primeira chamada
17	 *      a wp_upload_dir() popula esse cache e nenhuma chamada subsequente passa
18	 *      pelo filtro upload_dir. Por isso forcamos a primeira chamada com filtro
19	 *      local de prioridade 1 (antes do S3-Uploads em prioridade 10).
20	 *
21	 *   2) Filtro `s3_uploads_enabled` retorna false quando o caller atual e
22	 *      Elementor escrevendo CSS — proteção em camada para escritas que escapem
23	 *      o pre-warm (regeneracoes mid-request, hot reload, etc).
24	 *
25	 *   3) Arquivos servidos via path /wp-content/elementor-cache/{sites/N/} —
26	 *      esse path NAO bate com behaviors S3 do CloudFront, vai pro ALB normalmente.
27	 *
28	 * Cuidados:
29	 * - Multisite path-based: blog 1 vai pra /elementor-cache/, blog 2 pra /elementor-cache/sites/2/
30	 * - Pre-warm precisa rodar ANTES do S3-Uploads (`s3-uploads/s3-uploads.php`).
31	 *   Mu-plugins carregam antes de plugins, entao plugins_loaded priority 1 e
32	 *   suficiente. Se trocar para must-use plugin folder, garantir ordem alfabetica
33	 *   (b < s, ja garante).
34	 *
35	 * Validacao:
36	 *   wp eval 'echo \Elementor\Core\Files\Base::get_base_uploads_dir();'
37	 *   → deve retornar /var/www/.../wp-content/elementor-cache/[sites/N/]elementor/
38	 *
39	 *   ls /var/www/.../wp-content/elementor-cache/sites/2/elementor/css/
40	 *   → deve listar post-XX.css
41	 *
42	 *   curl -I /wp-content/elementor-cache/sites/2/elementor/css/post-72730.css
43	 *   → 200 OK servido pelo nginx (ALB origin)
44	 */
45	
46	if ( ! defined( 'ABSPATH' ) ) {
47		exit;
48	}
49	
50	const BIT_ELEMENTOR_CACHE_DIR_BASE = WP_CONTENT_DIR . '/elementor-cache';
51	const BIT_ELEMENTOR_CACHE_URL_PATH = '/wp-content/elementor-cache';
52	
53	/**
54	 * Resolve o basedir + baseurl locais para o blog corrente.
55	 *
56	 * @return array{basedir:string, baseurl:string}
57	 */
58	function bit_elc_get_local_paths() {
59		$blog_id = get_current_blog_id();
60		$suffix  = ( is_multisite() && $blog_id > 1 ) ? "/sites/{$blog_id}" : '';
61		$base    = BIT_ELEMENTOR_CACHE_DIR_BASE . $suffix;
62	
63		// Pegar URL do blog SEM passar por home_url()/get_home_url() — evita
64		// o filtro `home_url` que o WPML usa para injetar prefixo de idioma
65		// (ex: 'cultura/en' quando navegando em EN). Lemos direto do option
66		// 'home' do blog (raw) e removemos trailing slash.
67		if ( is_multisite() ) {
68			$blog_home = get_blog_option( $blog_id, 'home' );
69		} else {
70			$blog_home = get_option( 'home' );
71		}
72		$blog_home = is_string( $blog_home ) ? rtrim( $blog_home, '/' ) : '';
73		$url       = $blog_home . BIT_ELEMENTOR_CACHE_URL_PATH . $suffix;
74	
75		if ( ! is_dir( $base ) ) {
76			wp_mkdir_p( $base );
77		}
78	
79		return [ 'basedir' => $base, 'baseurl' => $url ];
80	}
81	
82	/**
83	 * Filtro upload_dir que devolve o path local do mu-plugin.
84	 * Usado APENAS durante o pre-warm — registrado e desregistrado em sequencia
85	 * para que o cache static do Elementor seja populado com path local na
86	 * primeira leitura.
87	 */
88	function bit_elc_force_local( $dirs ) {
89		$paths   = bit_elc_get_local_paths();
90		$subdir  = isset( $dirs['subdir'] ) ? $dirs['subdir'] : '';
91	
92		$dirs['basedir'] = $paths['basedir'];
93		$dirs['baseurl'] = $paths['baseurl'];
94		$dirs['path']    = $paths['basedir'] . $subdir;
95		$dirs['url']     = $paths['baseurl'] . $subdir;
96		$dirs['error']   = false;
97	
98		return $dirs;
99	}
100
